mapper.select:
SELECT 
FROM dorm_fee
WHERE residence_history_id = #{residenceHistoryId}
  AND target_year_month = #{targetYearMonth}
  AND deleted_at IS NULL

SELECT FROM dorm_fee df JOIN employee e ON e.employee_id = df.employee_id AND e.deleted_at IS NULL JOIN dormitory d ON d.dormitory_id = df.dormitory_id AND d.deleted_at IS NULL JOIN room r ON r.room_id = df.room_id AND r.deleted_at IS NULL JOIN residence_history rh ON rh.residence_history_id = df.residence_history_id AND rh.deleted_at IS NULL LEFT JOIN region rg ON rg.code = df.region AND rg.deleted_at IS NULL LEFT JOIN usage_type ut ON ut.code = df.usage_type_code AND ut.deleted_at IS NULL LEFT JOIN unit_price up ON up.unit_price_id = df.unit_price_id AND up.deleted_at IS NULL WHERE df.deleted_at IS NULL
AND df.employee_id ILIKE CONCAT('%', #{employeeId}, '%')
AND df.target_year_month = #{targetYearMonth}
AND df.status = #{status}
ORDER BY df.target_year_month DESC, df.dorm_fee_id LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM dorm_fee df
WHERE df.deleted_at IS NULL

    AND df.employee_id ILIKE CONCAT('%', #{employeeId}, '%')


    AND df.target_year_month = #{targetYearMonth}


    AND df.status = #{status}
